import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ConstructionSite {
  razaoSocial: string;
  nomeObra: string;
  endereco: string;
  setor: string;
  cidade: string;
  estado: string;
  cep: string;
}

export interface Cluster {
  name: string;
  sites: string[];
  region: string;
}

export interface DayRoute {
  day: string;
  visits: string[];
  estimatedTravelTime: string;
  totalTime: string;
}

export interface MonthAgenda {
  week: number;
  schedule: { [day: string]: string[] };
}

export interface AnalysisResult {
  diagnosis: string;
  currentEvaluation: {
    distanceAvg: string;
    timeAvg: string;
    criticalRegions: string[];
    efficiency: 'Alta' | 'Média' | 'Baixa';
    efficiencyDescription: string;
  };
  housingRecommendation: {
    topNeighborhoods: string[];
    centroidDescription: string;
    comparison: {
      currentAvgTime: string;
      suggestedAvgTime: string;
      monthlySavings: string;
    };
  };
  clusters: Cluster[];
  weeklyRoute: DayRoute[];
  monthlyAgenda: MonthAgenda[];
  timeSavingsSummary: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ConstructionSite, AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export async function analyzeLogistics(
  currentAddress: string,
  sites: ConstructionSite[]
): Promise<AnalysisResult> {
  const model = "gemini-3-pro-preview";

  const prompt = `
    Aja como um Agente Especialista em Otimização de Rotas e Moradia para São Paulo.

    DADOS DE ENTRADA:
    Endereço de Moradia Atual: ${currentAddress}
    Obras (Planilha): ${JSON.stringify(sites)}

    REGRAS DE NEGÓCIO:
    1. Geocodifique mentalmente (use sua base de conhecimento de SP) e identifique as zonas (Norte, Sul, Leste, Oeste, Centro, RMSP).
    2. Calcule o centroide geográfico das obras.
    3. Agrupe em clusters (distância <= 5km = mesmo dia, > 15km = dia exclusivo).
    4. Crie um roteiro semanal (Seg-Sex, máx 3 obras/dia).
    5. Crie uma agenda mensal (1 visita/obra por mês).
    6. Identifique a melhor região para morar que minimiza o tempo médio global.

    RETORNE APENAS JSON seguindo este esquema exato:
    {
      "diagnosis": "Resumo geográfico geral das obras",
      "currentEvaluation": {
        "distanceAvg": "km",
        "timeAvg": "minutos",
        "criticalRegions": ["regiões"],
        "efficiency": "Alta|Média|Baixa",
        "efficiencyDescription": "Por que essa classificação?"
      },
      "housingRecommendation": {
        "topNeighborhoods": ["Bairro 1", "Bairro 2", "Bairro 3"],
        "centroidDescription": "Localização do centroide",
        "comparison": {
          "currentAvgTime": "X min",
          "suggestedAvgTime": "Y min",
          "monthlySavings": "Z horas economizadas/mês"
        }
      },
      "clusters": [{"name": "Cluster X", "sites": ["Nome da Obra 1"], "region": "Zona"}],
      "weeklyRoute": [{"day": "Segunda-feira", "visits": ["Obra A", "Obra B"], "estimatedTravelTime": "X min", "totalTime": "Y min"}],
      "monthlyAgenda": [{"week": 1, "schedule": {"Segunda": ["Obra A"]}}],
      "timeSavingsSummary": "Resumo estratégico da economia"
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 15000 }
    },
  });

  return JSON.parse(response.text || "{}");
}

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { Cluster } from '../types';

interface Props {
  clusters: Cluster[];
}

export const SiteVisualizer: React.FC<Props> = ({ clusters }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current || clusters.length === 0) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll('*').remove();

    const width = 600;
    const height = 400;
    const padding = 40;

    // Simulate coordinates based on regions for visual mapping
    const regionCoords: Record<string, [number, number]> = {
      'Zona Norte': [300, 100],
      'Zona Sul': [300, 300],
      'Zona Leste': [450, 200],
      'Zona Oeste': [150, 200],
      'Centro': [300, 200],
      'RMSP': [500, 350],
      'Metropolitana': [500, 350]
    };

    const nodes: any[] = [];
    clusters.forEach((c, i) => {
      const base = regionCoords[c.region] || [300, 200];
      c.sites.forEach((site, si) => {
        nodes.push({
          id: site,
          cluster: c.name,
          region: c.region,
          x: base[0] + (Math.random() - 0.5) * 60,
          y: base[1] + (Math.random() - 0.5) * 60,
          color: d3.schemeTableau10[i % 10]
        });
      });
    });

    // Draw grid/regions
    svg.append('line').attr('x1', width/2).attr('y1', 0).attr('x2', width/2).attr('y2', height).attr('stroke', '#e2e8f0').attr('stroke-dasharray', '4');
    svg.append('line').attr('x1', 0).attr('y1', height/2).attr('x2', width).attr('y2', height/2).attr('stroke', '#e2e8f0').attr('stroke-dasharray', '4');

    // Labels
    const labels = [
      { t: 'NORTE', x: width/2, y: 20 },
      { t: 'SUL', x: width/2, y: height-10 },
      { t: 'OESTE', x: 40, y: height/2 },
      { t: 'LESTE', x: width-40, y: height/2 }
    ];
    svg.selectAll('.region-label')
      .data(labels)
      .enter()
      .append('text')
      .attr('x', d => d.x)
      .attr('y', d => d.y)
      .attr('text-anchor', 'middle')
      .attr('class', 'text-[10px] font-bold fill-slate-400')
      .text(d => d.t);

    // Draw sites
    const circles = svg.selectAll('.site')
      .data(nodes)
      .enter()
      .append('g')
      .attr('class', 'site-group cursor-help');

    circles.append('circle')
      .attr('cx', d => d.x)
      .attr('cy', d => d.y)
      .attr('r', 6)
      .attr('fill', d => d.color)
      .attr('stroke', 'white')
      .attr('stroke-width', 2);

    circles.append('title')
      .text(d => `${d.id}\nCluster: ${d.cluster}\nRegião: ${d.region}`);

  }, [clusters]);

  return (
    <div className="w-full bg-white rounded-xl p-4 shadow-sm border border-slate-100 overflow-hidden">
      <h3 className="text-sm font-semibold mb-4 text-slate-500 uppercase tracking-wider">Distribuição Geográfica e Clusterização</h3>
      <div className="flex justify-center">
        <svg ref={svgRef} viewBox="0 0 600 400" className="w-full max-w-[600px] h-auto"></svg>
      </div>
      <div className="mt-4 flex flex-wrap gap-3">
        {clusters.map((c, i) => (
           <div key={c.name} className="flex items-center gap-2 text-xs">
             <div className="w-3 h-3 rounded-full" style={{ backgroundColor: d3.schemeTableau10[i % 10] }}></div>
             <span className="text-slate-600">{c.name}</span>
           </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { ConstructionSite, AnalysisResult } from './types';
import { analyzeLogistics } from './services/geminiService';
import { SiteVisualizer } from './components/SiteVisualizer';
import { 
  MapPinIcon, 
  TableCellsIcon, 
  ArrowPathIcon, 
  HomeIcon, 
  CalendarIcon, 
  ClockIcon,
  CheckCircleIcon,
  ExclamationCircleIcon
} from '@heroicons/react/24/outline';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Legend } from 'recharts';

const App: React.FC = () => {
  const [currentAddress, setCurrentAddress] = useState('');
  const [rawInput, setRawInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const processInput = () => {
    const lines = rawInput.trim().split('\n');
    const sites: ConstructionSite[] = lines.map(line => {
      const cols = line.split('\t'); // Assume TAB separation from Excel paste
      return {
        razaoSocial: cols[0] || '',
        nomeObra: cols[1] || '',
        endereco: cols[2] || '',
        setor: cols[3] || '',
        cidade: cols[4] || '',
        estado: cols[5] || '',
        cep: cols[6] || ''
      };
    }).filter(s => s.nomeObra);
    return sites;
  };

  const handleRunAnalysis = async () => {
    if (!currentAddress) {
      setError('Por favor, insira seu endereço de moradia atual.');
      return;
    }
    const sites = processInput();
    if (sites.length === 0) {
      setError('Por favor, cole os dados da planilha (copie as colunas A a G).');
      return;
    }

    setLoading(true);
    setError(null);
    try {
      const data = await analyzeLogistics(currentAddress, sites);
      setResult(data);
    } catch (err) {
      console.error(err);
      setError('Ocorreu um erro na análise. Verifique sua conexão e tente novamente.');
    } finally {
      setLoading(false);
    }
  };

  const EfficiencyBadge = ({ type }: { type: string }) => {
    const colors = {
      'Alta': 'bg-emerald-100 text-emerald-700 border-emerald-200',
      'Média': 'bg-amber-100 text-amber-700 border-amber-200',
      'Baixa': 'bg-rose-100 text-rose-700 border-rose-200',
    };
    return (
      <span className={`px-2 py-1 rounded-full text-xs font-bold border ${colors[type as keyof typeof colors] || 'bg-slate-100'}`}>
        {type.toUpperCase()} EFICIÊNCIA
      </span>
    );
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <header className="mb-10 text-center sm:text-left flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight flex items-center gap-2">
            <MapPinIcon className="h-8 w-8 text-indigo-600" />
            Agente de Otimização de Rotas SP
          </h1>
          <p className="mt-2 text-slate-500 max-w-2xl text-sm">
            Estratégia logística, clusterização geográfica e planejamento de moradia para visitas técnicas em São Paulo.
          </p>
        </div>
        <div className="flex gap-2">
           <button 
             onClick={() => setResult(null)} 
             className="px-4 py-2 text-sm font-medium text-slate-600 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 transition-colors"
           >
             Novo Plano
           </button>
        </div>
      </header>

      {!result && (
        <main className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="space-y-6">
            <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
                <HomeIcon className="h-5 w-5 text-indigo-500" />
                Seu Ponto de Partida
              </h2>
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Endereço Atual (Moradia)</label>
                  <input
                    type="text"
                    value={currentAddress}
                    onChange={(e) => setCurrentAddress(e.target.value)}
                    placeholder="Ex: Av. Paulista, 1000 - Bela Vista, SP"
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                  />
                </div>
              </div>
            </section>

            <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
                <TableCellsIcon className="h-5 w-5 text-indigo-500" />
                Dados das Obras (Planilha)
              </h2>
              <p className="text-xs text-slate-500 mb-4 italic">
                Copie as colunas A até G da sua planilha e cole abaixo. 
                Colunas: Razão Social, Nome, Endereço, Setor, Cidade, UF, CEP.
              </p>
              <textarea
                value={rawInput}
                onChange={(e) => setRawInput(e.target.value)}
                placeholder="Cole os dados aqui..."
                className="w-full h-64 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all font-mono text-sm"
              />
            </section>

            {error && (
              <div className="p-4 bg-rose-50 border border-rose-100 text-rose-600 rounded-xl flex items-center gap-3">
                <ExclamationCircleIcon className="h-5 w-5" />
                <span className="text-sm font-medium">{error}</span>
              </div>
            )}

            <button
              onClick={handleRunAnalysis}
              disabled={loading}
              className={`w-full py-4 rounded-xl flex items-center justify-center gap-3 text-white font-bold transition-all shadow-lg ${
                loading ? 'bg-indigo-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-indigo-200 active:scale-[0.98]'
              }`}
            >
              {loading ? (
                <>
                  <ArrowPathIcon className="h-5 w-5 animate-spin" />
                  Otimizando logística e moradia...
                </>
              ) : (
                <>
                  <CheckCircleIcon className="h-5 w-5" />
                  Gerar Plano Estratégico
                </>
              )}
            </button>
          </div>

          <div className="hidden lg:flex flex-col justify-center items-center p-12 bg-indigo-50 rounded-3xl border border-indigo-100 border-dashed">
            <div className="text-center space-y-4">
              <div className="bg-white p-6 rounded-full shadow-lg inline-block">
                <MapPinIcon className="h-12 w-12 text-indigo-600" />
              </div>
              <h3 className="text-xl font-bold text-indigo-900">Análise de IA Urbana</h3>
              <p className="text-indigo-600 text-sm max-w-xs mx-auto">
                Utilizamos modelos avançados para clusterizar suas visitas e calcular a eficiência do seu deslocamento em tempo real.
              </p>
            </div>
          </div>
        </main>
      )}

      {result && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
          {/* Dashboard Summary */}
          <section className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 col-span-1 md:col-span-2">
               <h2 className="text-xl font-bold mb-4 text-slate-800">Diagnóstico Geográfico</h2>
               <p className="text-slate-600 leading-relaxed italic border-l-4 border-indigo-500 pl-4 py-2">
                 "{result.diagnosis}"
               </p>
            </div>
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 text-center flex flex-col justify-center items-center gap-2">
               <span className="text-sm font-medium text-slate-500">Eficiência Atual</span>
               <EfficiencyBadge type={result.currentEvaluation.efficiency} />
               <p className="text-xs text-slate-400 mt-2 px-4">{result.currentEvaluation.efficiencyDescription}</p>
            </div>
          </section>

          {/* Efficiency Stats and Recommendation */}
          <section className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 lg:col-span-1">
              <h3 className="text-lg font-bold mb-6 text-slate-800 flex items-center gap-2">
                <ClockIcon className="h-5 w-5 text-indigo-500" />
                Desempenho Atual
              </h3>
              <div className="space-y-6">
                <div className="flex justify-between items-end">
                  <span className="text-sm text-slate-500">Distância Média</span>
                  <span className="text-2xl font-black text-indigo-600">{result.currentEvaluation.distanceAvg}</span>
                </div>
                <div className="flex justify-between items-end">
                  <span className="text-sm text-slate-500">Tempo Médio Estimado</span>
                  <span className="text-2xl font-black text-indigo-600">{result.currentEvaluation.timeAvg}</span>
                </div>
                <div className="pt-4 border-t border-slate-100">
                   <h4 className="text-xs font-bold text-slate-400 uppercase mb-3">Regiões Críticas</h4>
                   <div className="flex flex-wrap gap-2">
                     {result.currentEvaluation.criticalRegions.map(r => (
                       <span key={r} className="px-2 py-1 bg-rose-50 text-rose-600 rounded text-xs font-medium">
                         {r}
                       </span>
                     ))}
                   </div>
                </div>
              </div>
            </div>

            <div className="bg-indigo-600 p-8 rounded-2xl shadow-xl shadow-indigo-100 text-white lg:col-span-2 flex flex-col md:flex-row gap-8 items-center">
              <div className="flex-1 space-y-4">
                <div className="flex items-center gap-3">
                  <HomeIcon className="h-8 w-8 text-indigo-200" />
                  <h3 className="text-2xl font-bold leading-tight">Melhor Região Sugerida para Morar</h3>
                </div>
                <div className="flex flex-wrap gap-2">
                  {result.housingRecommendation.topNeighborhoods.map(b => (
                    <span key={b} className="px-3 py-1 bg-white/20 backdrop-blur rounded-lg font-semibold text-lg">
                      {b}
                    </span>
                  ))}
                </div>
                <p className="text-indigo-100 text-sm italic">
                  Centroide Ponderado: {result.housingRecommendation.centroidDescription}
                </p>
              </div>
              <div className="bg-white/10 backdrop-blur-md rounded-2xl p-6 border border-white/20 w-full md:w-64">
                <h4 className="text-xs font-bold text-indigo-200 uppercase mb-4 text-center">Estimativa Mensal</h4>
                <div className="text-center">
                  <span className="block text-4xl font-black">{result.housingRecommendation.comparison.monthlySavings.split(' ')[0]}</span>
                  <span className="block text-sm text-indigo-200 font-medium">horas economizadas/mês</span>
                </div>
                <div className="mt-4 pt-4 border-t border-white/10 space-y-2 text-xs">
                  <div className="flex justify-between"><span>Atual:</span> <span>{result.housingRecommendation.comparison.currentAvgTime}</span></div>
                  <div className="flex justify-between font-bold"><span>Otimizado:</span> <span>{result.housingRecommendation.comparison.suggestedAvgTime}</span></div>
                </div>
              </div>
            </div>
          </section>

          {/* Map and Clusters */}
          <section className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <SiteVisualizer clusters={result.clusters} />
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <h3 className="text-lg font-bold mb-4 text-slate-800">Clusters Operacionais</h3>
              <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2">
                {result.clusters.map(c => (
                  <div key={c.name} className="p-4 rounded-xl bg-slate-50 border border-slate-100">
                    <div className="flex justify-between items-center mb-2">
                       <span className="font-bold text-slate-700">{c.name}</span>
                       <span className="text-[10px] font-bold px-2 py-0.5 bg-indigo-100 text-indigo-600 rounded uppercase">{c.region}</span>
                    </div>
                    <ul className="text-sm text-slate-500 space-y-1">
                      {c.sites.map(s => <li key={s} className="flex items-center gap-2"><div className="w-1 h-1 rounded-full bg-slate-300"></div>{s}</li>)}
                    </ul>
                  </div>
                ))}
              </div>
            </div>
          </section>

          {/* Weekly Routes */}
          <section>
            <h2 className="text-2xl font-bold text-slate-800 mb-6 flex items-center gap-2">
              <CalendarIcon className="h-6 w-6 text-indigo-500" />
              Planejamento Semanal Otimizado
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-4">
              {result.weeklyRoute.map((day, idx) => (
                <div key={idx} className="bg-white border border-slate-100 rounded-2xl overflow-hidden shadow-sm hover:shadow-md transition-shadow">
                  <div className="bg-slate-800 p-4 text-white">
                    <span className="block text-xs font-bold text-slate-400 uppercase tracking-widest">{day.day}</span>
                    <span className="text-xs font-medium text-emerald-400">{day.estimatedTravelTime} desloc.</span>
                  </div>
                  <div className="p-4 space-y-4 min-h-[180px] flex flex-col justify-between">
                    <div className="space-y-3">
                      {day.visits.length > 0 ? day.visits.map((v, vIdx) => (
                        <div key={vIdx} className="flex gap-3 items-start">
                          <span className="text-indigo-500 font-bold text-xs mt-1">{vIdx + 1}.</span>
                          <span className="text-sm font-medium text-slate-700 leading-tight">{v}</span>
                        </div>
                      )) : (
                        <span className="text-xs text-slate-400 italic">Nenhuma visita planejada</span>
                      )}
                    </div>
                    <div className="pt-3 border-t border-slate-50 flex items-center justify-between text-[10px] font-bold text-slate-400 uppercase">
                      <span>Tempo Total</span>
                      <span className="text-slate-600">{day.totalTime}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </section>

          {/* Monthly Agenda Preview */}
          <section className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
             <div className="flex items-center justify-between mb-8">
               <h3 className="text-xl font-bold text-slate-800">Agenda Mensal Consolidada</h3>
               <p className="text-sm text-slate-500 hidden md:block">Garantia de 1 visita por obra / mês</p>
             </div>
             <div className="space-y-8">
               {result.monthlyAgenda.map((week, wIdx) => (
                 <div key={wIdx} className="relative">
                   <div className="absolute -left-4 top-0 bottom-0 w-1 bg-indigo-100 rounded-full"></div>
                   <h4 className="text-sm font-black text-indigo-500 mb-4 ml-2">SEMANA {week.week}</h4>
                   <div className="grid grid-cols-1 md:grid-cols-5 gap-4 ml-2">
                     {Object.entries(week.schedule).map(([dayName, siteList], dIdx) => (
                        <div key={dIdx} className="p-3 bg-slate-50 rounded-lg border border-slate-100">
                          <span className="block text-[10px] font-bold text-slate-400 mb-2 uppercase">{dayName}</span>
                          <div className="space-y-1">
                            {siteList.map((site, sIdx) => (
                              <span key={sIdx} className="block text-xs font-semibold text-slate-600 truncate" title={site}>
                                {site}
                              </span>
                            ))}
                          </div>
                        </div>
                     ))}
                   </div>
                 </div>
               ))}
             </div>
          </section>

