  const [currentAddress, setCurrentAddress] = useState('');
  const [rawInput, setRawInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [printing, setPrinting] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const processInput = () => {
    const lines = rawInput.trim().split('\n');
    const sites: ConstructionSite[] = lines.map(line => {
      const cols = line.split('\t'); 
      return {
        razaoSocial: cols[0] || '',
        nomeObra: cols[1] || '',
        endereco: cols[2] || '',
        setor: cols[3] || '',
        cidade: cols[4] || '',
        estado: cols[5] || '',
        cep: cols[6] || ''
      };
    }).filter(s => s.nomeObra);
    return sites;
  };

  const handleRunAnalysis = async () => {
    if (!currentAddress) {
      setError('Por favor, insira seu endereço de moradia atual.');
      return;
    }
    const sites = processInput();
    if (sites.length === 0) {
      setError('Por favor, cole os dados da planilha (copie as colunas A a G).');
      return;
    }

    setLoading(true);
    setError(null);
    try {
      const data = await analyzeLogistics(currentAddress, sites);
      setResult(data);
    } catch (err) {
      console.error(err);
      setError('Ocorreu um erro na análise. Verifique sua conexão e tente novamente.');
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadPDF = useCallback((e: React.MouseEvent) => {
    // Prevenção total de bolhas de evento e comportamentos do navegador
    e.preventDefault();
    e.stopPropagation();

    setPrinting(true);

    // Pequeno delay para permitir que o estado do React (setPrinting) seja refletido na UI
    setTimeout(() => {
      try {
        const originalTitle = document.title;
        const dateStr = new Date().toLocaleDateString().replace(/\//g, '-');
        document.title = `Roteiro_Logistico_SP_${dateStr}`;

        window.print();

        document.title = originalTitle;
      } catch (err) {
        console.error("Erro ao disparar impressão:", err);
        alert("Não foi possível abrir a janela de impressão. Tente usar Ctrl+P ou verifique se o navegador está bloqueando janelas suspensas.");
      } finally {
        setPrinting(false);
      }
