                 Logística Diária (Modelo de Rota)
               </h2>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-6">
              {result.weeklyRoute.map((day, idx) => (
                <div key={idx} className="bg-white border border-slate-200 rounded-3xl overflow-hidden shadow-sm flex flex-col h-full">
                  <div className="bg-[#1e293b] p-5 text-white">
                    <h4 className="text-sm font-black uppercase tracking-widest mb-1">{day.day}</h4>
