import { SiteVisualizer } from './components/SiteVisualizer';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';
import { 
  MapPinIcon, 
  TableCellsIcon, 
  ArrowPathIcon, 
  HomeIcon, 
  CalendarIcon, 
  ClockIcon,
  CheckCircleIcon,
  DocumentArrowDownIcon,
  MapIcon
} from '@heroicons/react/24/outline';

const App: React.FC = () => {
  const [currentAddress, setCurrentAddress] = useState('');
  const [rawInput, setRawInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const reportRef = useRef<HTMLDivElement>(null);

  const processInput = () => {
    const lines = rawInput.trim().split('\n');
    const sites: ConstructionSite[] = lines.map(line => {
      const cols = line.split('\t'); 
      return {
        razaoSocial: cols[0] || '',
        nomeObra: cols[1] || '',
        endereco: cols[2] || '',
        setor: cols[3] || '',
        cidade: cols[4] || '',
        estado: cols[5] || '',
        cep: cols[6] || ''
      };
    }).filter(s => s.nomeObra);
    return sites;
  };

  const handleRunAnalysis = async () => {
    if (!currentAddress) {
      setError('Por favor, insira seu endereço de moradia atual.');
      return;
    }
    const sites = processInput();
    if (sites.length === 0) {
      setError('Por favor, cole os dados da planilha (copie as colunas A a G).');
      return;
    }

    setLoading(true);
    setError(null);
    try {
      const data = await analyzeLogistics(currentAddress, sites);
      setResult(data);
    } catch (err) {
      console.error(err);
      setError('Ocorreu um erro na análise. Verifique sua conexão e tente novamente.');
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadPDF = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (!reportRef.current) return;

    setExporting(true);

    try {
      const element = reportRef.current;

      // Captura o canvas em alta resolução
      const canvas = await html2canvas(element, {
        scale: 2.5, 
        useCORS: true,
        logging: false,
        backgroundColor: '#f8fafc',
        windowWidth: element.scrollWidth,
      });

      const imgData = canvas.toDataURL('image/jpeg', 0.95);

      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();

      // Largura da imagem no PDF será a largura total da página
      const imgWidth = pdfWidth;
      // Altura da imagem proporcional no PDF
      const imgHeight = (canvas.height * pdfWidth) / canvas.width;

      let heightLeft = imgHeight;
      let position = 0;

      // Primeira página
      pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
      heightLeft -= pdfHeight;

      // Adiciona novas páginas se o conteúdo for maior que uma folha A4
      while (heightLeft >= 0) {
        position = heightLeft - imgHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
        heightLeft -= pdfHeight;
      }

      const dateStr = new Date().toLocaleDateString().replace(/\//g, '-');
      pdf.save(`Relatorio_Logistico_SP_${dateStr}.pdf`);

    } catch (err) {
      console.error("Erro na geração do PDF:", err);
      window.print();
    } finally {
      setExporting(false);
    }
  };

  const EfficiencyBadge = ({ type }: { type: string }) => {
    const colors = {
      'Alta': 'bg-emerald-100 text-emerald-700 border-emerald-200',
      'Média': 'bg-amber-100 text-amber-700 border-amber-200',
      'Baixa': 'bg-rose-100 text-rose-700 border-rose-200',
    };
    return (
      <span className={`px-2 py-1 rounded-full text-xs font-bold border ${colors[type as keyof typeof colors] || 'bg-slate-100'}`}>
        {type.toUpperCase()} EFICIÊNCIA
      </span>
    );
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 print:p-0 print:max-w-none">
      <header className="mb-10 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 print:hidden">
        <div>
          <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight flex items-center gap-2">
            <MapPinIcon className="h-8 w-8 text-indigo-600" />
            SP Route Optimizer
          </h1>
          <p className="mt-1 text-slate-500 text-sm">
            Agente Especialista em Logística e Otimização de Moradia
          </p>
        </div>
        <div className="flex gap-2 items-center relative z-50">
           {result && (
             <button 
               onClick={handleDownloadPDF}
               disabled={exporting}
               type="button"
               className={`px-6 py-3 text-sm font-bold text-white rounded-xl transition-all flex items-center gap-2 shadow-xl cursor-pointer ${
                 exporting ? 'bg-indigo-400' : 'bg-indigo-600 hover:bg-indigo-700 active:scale-95 shadow-indigo-100'
               }`}
             >
               {exporting ? (
                 <ArrowPathIcon className="h-5 w-5 animate-spin" />
               ) : (
                 <DocumentArrowDownIcon className="h-5 w-5" />
               )}
               {exporting ? 'Gerando PDF Alta Definição...' : 'Download PDF Full Page'}
             </button>
           )}
           <button 
             onClick={() => setResult(null)} 
             type="button"
             className="px-5 py-3 text-sm font-medium text-slate-600 bg-white border border-slate-200 rounded-xl hover:bg-slate-50 active:scale-95 transition-colors cursor-pointer"
           >
             {result ? 'Novo Roteiro' : 'Limpar'}
           </button>
        </div>
      </header>

      {!result && (
        <main className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="space-y-6">
            <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
                <HomeIcon className="h-5 w-5 text-indigo-500" />
                Sua Localização Atual
              </h2>
              <input
                type="text"
                value={currentAddress}
                onChange={(e) => setCurrentAddress(e.target.value)}
                placeholder="Ex: Próximo à Estação Vila Mariana, SP"
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              />
            </section>

            <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
                <TableCellsIcon className="h-5 w-5 text-indigo-500" />
                Dados da Planilha (Obras)
              </h2>
              <textarea
                value={rawInput}
                onChange={(e) => setRawInput(e.target.value)}
                placeholder="Cole aqui as colunas A a G da planilha..."
                className="w-full h-64 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none font-mono text-xs leading-relaxed"
              />
            </section>

            {error && (
              <div className="p-4 bg-rose-50 text-rose-600 rounded-xl text-sm font-medium border border-rose-100">
                {error}
              </div>
            )}

            <button
              onClick={handleRunAnalysis}
              disabled={loading}
              className={`w-full py-4 rounded-xl flex items-center justify-center gap-3 text-white font-bold transition-all shadow-lg ${
                loading ? 'bg-indigo-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'
              }`}
            >
              {loading ? <ArrowPathIcon className="h-5 w-5 animate-spin" /> : <CheckCircleIcon className="h-5 w-5" />}
              {loading ? 'Analisando logística de SP...' : 'Gerar Planejamento Estratégico'}
            </button>
          </div>

          <div className="hidden lg:flex flex-col justify-center items-center p-12 bg-slate-100 rounded-3xl border border-slate-200 border-dashed">
             <div className="text-center space-y-4">
               <div className="bg-white p-5 rounded-3xl shadow-sm inline-block">
                 <MapIcon className="h-10 w-10 text-indigo-500" />
               </div>
               <h3 className="text-xl font-bold text-slate-800">Logística sobre Trilhos</h3>
               <p className="text-slate-500 text-sm max-w-sm mx-auto">
                 "Otimizamos suas visitas mensais priorizando a malha metroviária de São Paulo para previsibilidade e economia."
               </p>
             </div>
          </div>
        </main>
      )}

      {result && (
        <div ref={reportRef} className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-700 bg-slate-50 p-8 rounded-[40px]">
          {/* Header Stats */}
          <section className="grid grid-cols-1 md:grid-cols-4 gap-6">
            <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm md:col-span-2">
               <h2 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-2">Diagnóstico Estratégico</h2>
               <p className="text-slate-700 text-lg font-medium leading-snug">"{result.diagnosis}"</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm text-center">
               <span className="text-xs font-bold text-slate-400 uppercase">Eficiência Geral</span>
               <div className="mt-2"><EfficiencyBadge type={result.currentEvaluation.efficiency} /></div>
            </div>
            <div className="bg-indigo-600 p-6 rounded-2xl shadow-lg shadow-indigo-100 text-white text-center">
               <span className="text-xs font-bold text-indigo-200 uppercase">Economia no Mês</span>
               <div className="text-2xl font-black mt-1">{result.housingRecommendation.comparison.monthlySavings}</div>
            </div>
          </section>

          {/* Site Visualizer */}
          <section className="bg-white p-8 rounded-3xl border border-slate-100">
             <div className="mb-6 flex items-center gap-3">
                <MapIcon className="h-6 w-6 text-indigo-500" />
                <h3 className="text-xl font-black text-slate-800">Distribuição por Eixos de Transporte</h3>
             </div>
             <SiteVisualizer clusters={result.clusters} />
          </section>

          {/* Weekly Pattern Cards */}
          <section>
            <div className="flex items-center justify-between mb-8">
               <h2 className="text-2xl font-black text-slate-800 flex items-center gap-3">
                 <ClockIcon className="h-7 w-7 text-indigo-500" />
                 Logística Diária (Modelo de Rota)
               </h2>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-6">
              {result.weeklyRoute.map((day, idx) => (
                <div key={idx} className="bg-white border border-slate-200 rounded-3xl overflow-hidden shadow-sm flex flex-col h-full">
                  <div className="bg-[#1e293b] p-5 text-white">
                    <h4 className="text-sm font-black uppercase tracking-widest mb-1">{day.day}</h4>
                    <span className="text-[10px] font-bold text-indigo-300 block leading-tight">{day.estimatedTravelTime}</span>
                  </div>
                  <div className="p-6 flex-1 space-y-4">
                    {day.visits.length > 0 ? day.visits.map((v, vIdx) => (
                      <div key={vIdx} className="flex gap-2">
                        <span className="text-indigo-500 font-black text-xs mt-0.5">{vIdx + 1}.</span>
                        <span className="text-sm font-bold text-slate-700 leading-tight">{v}</span>
                      </div>
                    )) : (
                      <div className="text-center py-4 text-xs text-slate-300 italic">Livre</div>
                    )}
                    <div className="pt-4 border-t border-slate-100 mt-auto">
                      <div className="flex justify-between items-center text-[10px] font-black text-slate-400 uppercase">
                        <span>Tempo</span>
                        <span className="text-slate-800">{day.totalTime}</span>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </section>

          {/* Monthly Agenda */}
          <section className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm">
             <div className="mb-10">
                <h3 className="text-2xl font-black text-slate-800 underline decoration-indigo-200 underline-offset-8">Agenda Mensal Consolidada</h3>
                <p className="text-sm text-slate-400 mt-4 italic">Obras distribuídas estrategicamente para maximizar o uso da malha ferroviária.</p>
             </div>

             <div className="space-y-12">
               {result.monthlyAgenda.map((week, wIdx) => (
                 <div key={wIdx} className="group">
                    <div className="flex items-center gap-4 mb-6">
                       <span className="h-px bg-slate-100 flex-1"></span>
                       <span className="px-4 py-1.5 bg-slate-800 text-white rounded-full text-[10px] font-black tracking-widest uppercase">Semana {week.week}</span>
                       <span className="h-px bg-slate-100 flex-1"></span>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
                      {['Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta'].map((dayName) => {
                        const sites = (week.schedule as any)[dayName] || [];
                        return (
                          <div key={dayName} className="p-5 bg-slate-50 rounded-2xl border border-transparent hover:border-indigo-100 hover:bg-white hover:shadow-xl transition-all">
                            <span className="block text-[10px] font-black text-slate-400 mb-3 uppercase tracking-widest">{dayName}</span>
                            <div className="space-y-2">
                              {sites.length > 0 ? (sites as string[]).map((site, sIdx) => (
                                <div key={sIdx} className="flex items-start gap-2">
                                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 mt-1.5 shrink-0"></div>
                                  <span className="text-xs font-bold text-slate-700 leading-tight" title={site}>{site}</span>
                                </div>
                              )) : (
                                <span className="text-[10px] text-slate-300 italic">Disponível</span>
                              )}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                 </div>
               ))}
             </div>
          </section>

          {/* Housing Recommendations */}
          <section className="bg-indigo-900 rounded-[40px] p-10 text-white flex flex-col lg:flex-row gap-10 items-center">
             <div className="flex-1 space-y-6">
                <h3 className="text-3xl font-black">Estratégia de Moradia</h3>
                <div className="flex flex-wrap gap-3">
                   {result.housingRecommendation.topNeighborhoods.map(b => (
                     <span key={b} className="px-5 py-3 bg-white/10 rounded-2xl font-bold border border-white/10">{b}</span>
                   ))}
                </div>
                <p className="text-indigo-200 text-sm leading-relaxed max-w-xl">
                  {result.housingRecommendation.centroidDescription}
                </p>
             </div>
             <div className="w-full lg:w-80 bg-white/5 rounded-3xl p-8 border border-white/10 backdrop-blur">
                <div className="space-y-6">
                  <div>
                    <span className="block text-[10px] font-black text-indigo-300 uppercase mb-1">Média Otimizada</span>
                    <span className="text-4xl font-black text-emerald-400">{result.housingRecommendation.comparison.suggestedAvgTime}</span>
                  </div>
                  <div className="pt-6 border-t border-white/10 text-xs text-indigo-200 italic">
                    Otimização de {result.housingRecommendation.comparison.monthlySavings} mensais.
                  </div>
                </div>
             </div>
          </section>

          <section className="bg-emerald-50 border-2 border-emerald-100 p-10 rounded-[40px] text-center max-w-4xl mx-auto">
             <h3 className="text-xl font-black text-emerald-800 mb-4 uppercase tracking-wider">Considerações Finais</h3>
             <p className="text-emerald-700 font-medium leading-relaxed">
               {result.timeSavingsSummary}
             </p>
          </section>

          <footer className="mt-10 py-6 text-center border-t border-slate-200">
             <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest italic">Relatório Gerado em {new Date().toLocaleDateString()} • SP Route Optimizer</p>
          </footer>
        </div>
      )}

      {!result && (
        <footer className="mt-20 py-10 border-t border-slate-100 text-center">
           <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest italic">SP Route Optimizer • Logística sobre Trilhos • 2025</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef } from 'react';
import { ConstructionSite, AnalysisResult } from './types';
import { analyzeLogistics } from './services/geminiService';
import { SiteVisualizer } from './components/SiteVisualizer';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';
import { 
  MapPinIcon, 
  TableCellsIcon, 
  ArrowPathIcon, 
  HomeIcon, 
  CalendarIcon, 
  ClockIcon,
  CheckCircleIcon,
  DocumentArrowDownIcon,
  MapIcon
} from '@heroicons/react/24/outline';

const App: React.FC = () => {
  const [currentAddress, setCurrentAddress] = useState('');
  const [rawInput, setRawInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const reportRef = useRef<HTMLDivElement>(null);

  const processInput = () => {
    const lines = rawInput.trim().split('\n');
    const sites: ConstructionSite[] = lines.map(line => {
      const cols = line.split('\t'); 
      return {
        razaoSocial: cols[0] || '',
        nomeObra: cols[1] || '',
        endereco: cols[2] || '',
        setor: cols[3] || '',
        cidade: cols[4] || '',
        estado: cols[5] || '',
        cep: cols[6] || ''
      };
    }).filter(s => s.nomeObra);
    return sites;
  };

  const handleRunAnalysis = async () => {
    if (!currentAddress) {
      setError('Por favor, insira seu endereço de moradia atual.');
      return;
    }
    const sites = processInput();
    if (sites.length === 0) {
      setError('Por favor, cole os dados da planilha (copie as colunas A a G).');
      return;
    }

    setLoading(true);
    setError(null);
    try {
      const data = await analyzeLogistics(currentAddress, sites);
      setResult(data);
    } catch (err) {
      console.error("Erro na análise:", err);
      setError('Ocorreu um erro na análise. Verifique se copiou as colunas corretamente.');
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadPDF = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (!reportRef.current) return;

    setExporting(true);

    try {
      const element = reportRef.current;

      // Captura o elemento com escala para qualidade mas sem estourar memória
      const canvas = await html2canvas(element, {
        scale: 2,
        useCORS: true,
        logging: false,
        backgroundColor: '#f8fafc',
        width: element.offsetWidth,
        height: element.scrollHeight
      });

      const imgData = canvas.toDataURL('image/jpeg', 0.9);

      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();

      // Cálculo para que a largura da imagem seja exatamente a largura da página PDF (210mm para A4)
      const imgWidth = pdfWidth;
      const imgHeight = (canvas.height * pdfWidth) / canvas.width;

      let heightLeft = imgHeight;
      let position = 0;

      // Adiciona a primeira página
      pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
      heightLeft -= pdfHeight;

      // Adiciona as páginas subsequentes se necessário
      while (heightLeft > 0) {
        position = heightLeft - imgHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
        heightLeft -= pdfHeight;
      }

      const dateStr = new Date().toLocaleDateString().replace(/\//g, '-');
      pdf.save(`Relatorio_Logistica_SP_${dateStr}.pdf`);

    } catch (err) {
      console.error("Falha ao gerar PDF:", err);
      alert("Houve um problema ao gerar o PDF. Tentando abrir o modo de impressão do sistema...");
      window.print();
    } finally {
      setExporting(false);
    }
  };

  const EfficiencyBadge = ({ type }: { type: string }) => {
    const colors = {
      'Alta': 'bg-emerald-100 text-emerald-700 border-emerald-200',
      'Média': 'bg-amber-100 text-amber-700 border-amber-200',
      'Baixa': 'bg-rose-100 text-rose-700 border-rose-200',
    };
    return (
      <span className={`px-2 py-1 rounded-full text-xs font-bold border ${colors[type as keyof typeof colors] || 'bg-slate-100'}`}>
        {type.toUpperCase()} EFICIÊNCIA
      </span>
    );
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <header className="mb-10 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight flex items-center gap-2">
            <MapPinIcon className="h-8 w-8 text-indigo-600" />
            SP Route Optimizer
          </h1>
          <p className="mt-1 text-slate-500 text-sm">
            Otimização Estratégica de Logística e Moradia
          </p>
        </div>
        <div className="flex gap-2 items-center">
           {result && (
             <button 
               onClick={handleDownloadPDF}
               disabled={exporting}
               className={`px-6 py-3 text-sm font-bold text-white rounded-xl transition-all flex items-center gap-2 shadow-xl ${
                 exporting ? 'bg-indigo-400 cursor-wait' : 'bg-indigo-600 hover:bg-indigo-700 active:scale-95'
               }`}
             >
               {exporting ? (
                 <ArrowPathIcon className="h-5 w-5 animate-spin" />
               ) : (
                 <DocumentArrowDownIcon className="h-5 w-5" />
               )}
               {exporting ? 'Ocupando Páginas...' : 'Download PDF Full'}
             </button>
           )}
           <button 
             onClick={() => setResult(null)} 
             className="px-5 py-3 text-sm font-medium text-slate-600 bg-white border border-slate-200 rounded-xl hover:bg-slate-50 transition-colors"
           >
             {result ? 'Novo Cálculo' : 'Limpar'}
           </button>
        </div>
      </header>

      {!result && (
        <main className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in fade-in duration-500">
          <div className="space-y-6">
            <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
                <HomeIcon className="h-5 w-5 text-indigo-500" />
                Moradia Atual
              </h2>
              <input
                type="text"
                value={currentAddress}
                onChange={(e) => setCurrentAddress(e.target.value)}
                placeholder="Ex: Próximo ao Metrô Santa Cruz, SP"
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              />
            </section>

            <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
                <TableCellsIcon className="h-5 w-5 text-indigo-500" />
                Colar Dados (A-G)
              </h2>
              <textarea
                value={rawInput}
                onChange={(e) => setRawInput(e.target.value)}
                placeholder="Cole os dados da planilha aqui..."
                className="w-full h-64 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none font-mono text-xs"
              />
            </section>

